/*
 * Disk Scheduling Algorithms Implementation in C
 * ===============================================
 * Topic: Operating Systems - Disk Scheduling
 * Example: Queue = [98, 183, 37, 122, 14, 124, 65, 67], Head = 53
 * 
 * Compile: gcc disk_scheduling.c -o disk_scheduling
 * Run: ./disk_scheduling
 */

#include <stdio.h>
#include <stdlib.h>
#include <string.h>

#define MAX_REQUESTS 100
#define DISK_RANGE 199

// Structure to hold algorithm results
typedef struct {
 int service_order[MAX_REQUESTS];
 int order_length;
 int total_head_movement;
} DiskScheduleResult;

// Function prototypes
int abs_diff(int a, int b);
void print_results(char *algo_name, DiskScheduleResult *result);

// ============================================
// 1. FCFS (First Come First Served)
// ============================================
void fcfs(int requests[], int num_requests, int head, DiskScheduleResult *result) {
 result->order_length = num_requests;
 result->total_head_movement = 0;

 printf("\n--- FCFS (First Come First Served) ---\n");
 printf("Start at: %d\n", head);

 int current_head = head;

 for (int i = 0; i < num_requests; i++) {
 result->service_order[i] = requests[i];
 int movement = abs_diff(requests[i], current_head);

 printf("Step %d: %d -> %d | Movement: %d\n", 
 i + 1, current_head, requests[i], movement);

 result->total_head_movement += movement;
 current_head = requests[i];
 }

 printf("Total Head Movement: %d cylinders\n", result->total_head_movement);
}

// ============================================
// 2. SSTF (Shortest Seek Time First)
// ============================================
void sstf(int requests[], int num_requests, int head, DiskScheduleResult *result) {
 int remaining[MAX_REQUESTS];
 memcpy(remaining, requests, num_requests * sizeof(int));

 result->order_length = 0;
 result->total_head_movement = 0;
 int current_head = head;

 printf("\n--- SSTF (Shortest Seek Time First) ---\n");
 printf("Start at: %d\n", head);

 int step = 1;
 while (result->order_length < num_requests) {
 int closest_idx = -1;
 int closest_dist = 999999;

 // Find closest request to current head
 for (int i = 0; i < num_requests; i++) {
 if (remaining[i] != -1) {
 int dist = abs_diff(remaining[i], current_head);
 if (dist < closest_dist) {
 closest_dist = dist;
 closest_idx = i;
 }
 }
 }

 // Service the closest request
 int served = remaining[closest_idx];
 result->service_order[result->order_length++] = served;

 printf("Step %d: %d -> %d | Movement: %d\n", 
 step++, current_head, served, closest_dist);

 result->total_head_movement += closest_dist;
 current_head = served;
 remaining[closest_idx] = -1; // Mark as served
 }

 printf("Total Head Movement: %d cylinders\n", result->total_head_movement);
}

// ============================================
// 3. SCAN (Elevator Algorithm)
// ============================================
void scan_algorithm(int requests[], int num_requests, int head, 
 DiskScheduleResult *result, int direction) {
 // Sort requests
 int sorted[MAX_REQUESTS];
 memcpy(sorted, requests, num_requests * sizeof(int));

 // Bubble sort
 for (int i = 0; i < num_requests - 1; i++) {
 for (int j = 0; j < num_requests - i - 1; j++) {
 if (sorted[j] > sorted[j + 1]) {
 int temp = sorted[j];
 sorted[j] = sorted[j + 1];
 sorted[j + 1] = temp;
 }
 }
 }

 // Split into left and right of head
 int left[MAX_REQUESTS], right[MAX_REQUESTS];
 int left_count = 0, right_count = 0;

 for (int i = 0; i < num_requests; i++) {
 if (sorted[i] < head) {
 left[left_count++] = sorted[i];
 } else {
 right[right_count++] = sorted[i];
 }
 }

 result->order_length = 0;
 result->total_head_movement = 0;
 int current_head = head;
 int step = 1;

 printf("\n--- SCAN (Elevator Algorithm) ---\n");
 printf("Start at: %d, Direction: %s\n", 
 head, direction == 0 ? "LEFT" : "RIGHT");

 if (direction == 0) { // Moving left first
 // Service all requests to the left (going toward 0)
 // Process in reverse order (closest first)
 for (int i = left_count - 1; i >= 0; i--) {
 int movement = abs_diff(current_head, left[i]);
 result->service_order[result->order_length++] = left[i];

 printf("Step %d: %d -> %d | Movement: %d\n", 
 step++, current_head, left[i], movement);

 result->total_head_movement += movement;
 current_head = left[i];
 }

 // Jump to beginning of disk (0)
 if (left_count > 0) {
 int movement = abs_diff(current_head, 0);
 printf("Step %d: %d -> %d (jump to disk edge) | Movement: %d\n",
 step++, current_head, 0, movement);
 result->total_head_movement += movement;
 current_head = 0;
 }

 // Now service all requests to the right
 for (int i = 0; i < right_count; i++) {
 int movement = abs_diff(current_head, right[i]);
 result->service_order[result->order_length++] = right[i];

 printf("Step %d: %d -> %d | Movement: %d\n", 
 step++, current_head, right[i], movement);

 result->total_head_movement += movement;
 current_head = right[i];
 }
 } else { // Moving right first
 // Service all requests to the right (going toward 199)
 for (int i = 0; i < right_count; i++) {
 int movement = abs_diff(current_head, right[i]);
 result->service_order[result->order_length++] = right[i];

 printf("Step %d: %d -> %d | Movement: %d\n", 
 step++, current_head, right[i], movement);

 result->total_head_movement += movement;
 current_head = right[i];
 }

 // Jump to end of disk (199)
 if (right_count > 0) {
 int movement = abs_diff(current_head, DISK_RANGE);
 printf("Step %d: %d -> %d (jump to disk edge) | Movement: %d\n",
 step++, current_head, DISK_RANGE, movement);
 result->total_head_movement += movement;
 current_head = DISK_RANGE;
 }

 // Now service all requests to the left
 for (int i = left_count - 1; i >= 0; i--) {
 int movement = abs_diff(current_head, left[i]);
 result->service_order[result->order_length++] = left[i];

 printf("Step %d: %d -> %d | Movement: %d\n", 
 step++, current_head, left[i], movement);

 result->total_head_movement += movement;
 current_head = left[i];
 }
 }

 printf("Total Head Movement: %d cylinders\n", result->total_head_movement);
}

// Helper function: absolute difference
int abs_diff(int a, int b) {
 return (a > b) ? (a - b) : (b - a);
}

// Print results summary
void print_results(char *algo_name, DiskScheduleResult *result) {
 printf("\n=== %s Results ===\n", algo_name);
 printf("Service Order: [");
 for (int i = 0; i < result->order_length; i++) {
 printf("%d", result->service_order[i]);
 if (i < result->order_length - 1) printf(", ");
 }
 printf("]\n");
 printf("Total Head Movement: %d cylinders\n", result->total_head_movement);
}

// ============================================
// Main Function
// ============================================
int main() {
 // Given example from textbook
 int requests[] = {98, 183, 37, 122, 14, 124, 65, 67};
 int num_requests = sizeof(requests) / sizeof(requests[0]);
 int head_start = 53;

 printf("======================================================\n");
 printf(" DISK SCHEDULING ALGORITHMS - C IMPLEMENTATION\n");
 printf("======================================================\n");
 printf("Request Queue: ");
 for (int i = 0; i < num_requests; i++) {
 printf("%d ", requests[i]);
 }
 printf("\nInitial Head Position: %d\n", head_start);
 printf("Disk Range: 0 - %d\n", DISK_RANGE);

 DiskScheduleResult result;

 // Run FCFS
 fcfs(requests, num_requests, head_start, &result);
 print_results("FCFS", &result);

 // Run SSTF
 sstf(requests, num_requests, head_start, &result);
 print_results("SSTF", &result);

 // Run SCAN (left)
 scan_algorithm(requests, num_requests, head_start, &result, 0); // 0 = left
 print_results("SCAN-LEFT", &result);

 // Run SCAN (right)
 scan_algorithm(requests, num_requests, head_start, &result, 1); // 1 = right
 print_results("SCAN-RIGHT", &result);

 printf("\n======================================================\n");
 printf("Note: SCAN goes to disk edge before reversing.\n");
 printf("LOOK (not shown) is similar but only goes to last request.\n");
 printf("======================================================\n");

 return 0;
}

/**
 * Disk Scheduling Algorithms - Java Implementation
 * =================================================
 * Topic: Operating Systems - Disk Scheduling
 * Example: Queue = [98, 183, 37, 122, 14, 124, 65, 67], Head = 53
 * 
 * This implementation focuses on LOOK and C-LOOK algorithms
 * which are most commonly used in modern operating systems.
 */

import java.util.*;

public class DiskScheduling {

 private static final int DISK_RANGE = 199;

 // ============================================
 // Result class to store algorithm output
 // ============================================
 static class ScheduleResult {
 List<Integer> serviceOrder;
 int totalHeadMovement;
 List<Integer> headMovements;

 public ScheduleResult() {
 this.serviceOrder = new ArrayList<>();
 this.headMovements = new ArrayList<>();
 this.totalHeadMovement = 0;
 }

 public void addMovement(int from, int to) {
 int movement = Math.abs(to - from);
 headMovements.add(movement);
 totalHeadMovement += movement;
 }
 }

 // ============================================
 // FCFS Implementation
 // ============================================
 public static ScheduleResult fcfs(List<Integer> requests, int head) {
 ScheduleResult result = new ScheduleResult();
 int currentHead = head;

 for (int request : requests) {
 result.serviceOrder.add(request);
 result.addMovement(currentHead, request);
 currentHead = request;
 }

 return result;
 }

 // ============================================
 // SSTF Implementation
 // ============================================
 public static ScheduleResult sstf(List<Integer> requests, int head) {
 ScheduleResult result = new ScheduleResult();
 List<Integer> remaining = new ArrayList<>(requests);
 int currentHead = head;

 while (!remaining.isitsEmpty()) {
 // Find closest request
 int closestIdx = 0;
 int closestDist = Math.abs(remaining.get(0) - currentHead);

 for (int i = 1; i < remaining.size(); i++) {
 int dist = Math.abs(remaining.get(i) - currentHead);
 if (dist < closestDist) {
 closestDist = dist;
 closestIdx = i;
 }
 }

 int served = remaining.get(closestIdx);
 result.serviceOrder.add(served);
 result.addMovement(currentHead, served);
 currentHead = served;
 remaining.remove(closestIdx);
 }

 return result;
 }

 // ============================================
 // LOOK Algorithm (Enhanced SCAN)
 // ============================================
 public static ScheduleResult look(List<Integer> requests, int head, 
 boolean goLeftFirst) {
 ScheduleResult result = new ScheduleResult();
 List<Integer> sorted = new ArrayList<>(requests);
 Collections.sort(sorted);

 int currentHead = head;

 // Split into left and right of head
 List<Integer> left = new ArrayList<>();
 List<Integer> right = new ArrayList<>();

 for (int req : sorted) {
 if (req < head) left.add(req);
 else right.add(req);
 }

 if (goLeftFirst) {
 // Process left (toward 0), then reverse to right
 Collections.reverse(left);

 for (int req : left) {
 result.serviceOrder.add(req);
 result.addMovement(currentHead, req);
 currentHead = req;
 }

 // Reverse direction and process right
 for (int req : right) {
 result.serviceOrder.add(req);
 result.addMovement(currentHead, req);
 currentHead = req;
 }
 } else {
 // Process right first, then left
 for (int req : right) {
 result.serviceOrder.add(req);
 result.addMovement(currentHead, req);
 currentHead = req;
 }

 Collections.reverse(left);
 for (int req : left) {
 result.serviceOrder.add(req);
 result.addMovement(currentHead, req);
 currentHead = req;
 }
 }

 return result;
 }

 // ============================================
 // C-LOOK Algorithm
 // ============================================
 public static ScheduleResult clook(List<Integer> requests, int head,
 boolean goRightFirst) {
 ScheduleResult result = new ScheduleResult();
 List<Integer> sorted = new ArrayList<>(requests);
 Collections.sort(sorted);

 int currentHead = head;

 // Split into left and right
 List<Integer> left = new ArrayList<>();
 List<Integer> right = new ArrayList<>();

 for (int req : sorted) {
 if (req < head) left.add(req);
 else right.add(req);
 }

 if (goRightFirst) {
 // Process all to the right, jump to smallest left, process left
 for (int req : right) {
 result.serviceOrder.add(req);
 result.addMovement(currentHead, req);
 currentHead = req;
 }

 // Jump to beginning (to smallest request, not to cylinder 0)
 if (!right.isEmpty() && !left.isEmpty()) {
 int jumpMovement = Math.abs(currentHead - left.get(0));
 result.headMovements.add(jumpMovement); // Jump without servicing
 result.totalHeadMovement += jumpMovement;
 currentHead = left.get(0);
 }

 // Process remaining left requests
 for (int req : left) {
 result.serviceOrder.add(req);
 result.addMovement(currentHead, req);
 currentHead = req;
 }
 } else {
 // Mirror: left first, jump to largest right
 Collections.reverse(left);

 for (int req : left) {
 result.serviceOrder.add(req);
 result.addMovement(currentHead, req);
 currentHead = req;
 }

 if (!left.isEmpty() && !right.isEmpty()) {
 int jumpMovement = Math.abs(currentHead - right.get(right.size() - 1));
 result.headMovements.add(jumpMovement);
 result.totalHeadMovement += jumpMovement;
 currentHead = right.get(right.size() - 1);
 }

 Collections.reverse(right);
 for (int req : right) {
 result.serviceOrder.add(req);
 result.addMovement(currentHead, req);
 currentHead = req;
 }
 }

 return result;
 }

 // ============================================
 // Print Results
 // ============================================
 public static void printResults(String algorithmName, ScheduleResult result) {
 System.out.println("\n" + "=".repeat(50));
 System.out.println("Algorithm: " + algorithmName);
 System.out.println("=".repeat(50));

 System.out.print("Service Order: [");
 for (int i = 0; i < result.serviceOrder.size(); i++) {
 System.out.print(result.serviceOrder.get(i));
 if (i < result.serviceOrder.size() - 1) System.out.print(" -> ");
 }
 System.out.println("]");

 System.out.print("Head Movements: [");
 for (int i = 0; i < result.headMovements.size(); i++) {
 System.out.print(result.headMovements.get(i));
 if (i < result.headMovements.size() - 1) System.out.print(", ");
 }
 System.out.println("]");

 System.out.println("TOTAL HEAD MOVEMENT: " + result.totalHeadMovement + " cylinders");
 }

 // ============================================
 // Main Method
 // ============================================
 public static void main(String[] args) {
 // Input data from textbook example
 List<Integer> requests = Arrays.asList(98, 183, 37, 122, 14, 124, 65, 67);
 int headStart = 53;

 System.out.println("╔════════════════════════════════════════════════════╗");
 System.out.println("║ DISK SCHEDULING ALGORITHMS - JAVA IMPLEMENTATION ║");
 System.out.println("╚════════════════════════════════════════════════════╝");
 System.out.println("Request Queue: " + requests);
 System.out.println("Initial Head Position: " + headStart);
 System.out.println("Disk Range: 0 - " + DISK_RANGE);

 // Run all algorithms
 ScheduleResult fcfsResult = fcfs(requests, headStart);
 printResults("FCFS (First Come First Served)", fcfsResult);

 ScheduleResult sstfResult = sstf(requests, headStart);
 printResults("SSTF (Shortest Seek Time First)", sstfResult);

 ScheduleResult lookLeft = look(requests, headStart, true);
 printResults("LOOK (Going Left First)", lookLeft);

 ScheduleResult lookRight = look(requests, headStart, false);
 printResults("LOOK (Going Right First)", lookRight);

 ScheduleResult clookRight = clook(requests, headStart, true);
 printResults("C-LOOK (Going Right First)", clookRight);

 // Summary table
 System.out.println("\n" + "=".repeat(60));
 System.out.println(" PERFORMANCE COMPARISON SUMMARY");
 System.out.println("=".repeat(60));
 System.out.printf("%-35s %15s%n", "Algorithm", "Head Movement");
 System.out.println("-".repeat(60));
 System.out.printf("%-35s %15d%n", "FCFS", fcfsResult.totalHeadMovement);
 System.out.printf("%-35s %15d%n", "SSTF", sstfResult.totalHeadMovement);
 System.out.printf("%-35s %15d%n", "LOOK (left)", lookLeft.totalHeadMovement);
 System.out.printf("%-35s %15d%n", "LOOK (right)", lookRight.totalHeadMovement);
 System.out.printf("%-35s %15d%n", "C-LOOK (right)", clookRight.totalHeadMovement);

 // Find best
 int best = Math.min(Math.min(fcfsResult.totalHeadMovement, sstfResult.totalHeadMovement),
 Math.min(lookLeft.totalHeadMovement, 
 Math.min(lookRight.totalHeadMovement, clookRight.totalHeadMovement)));
 System.out.println("-".repeat(60));
 System.out.println("Best performer: LOOK/C-LOOK algorithms");
 }
}
